import React, { useEffect, useMemo, useState } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import PizzaCard from '../../components/pizza/PizzaCard'
import Loader from '../../components/common/Loader'
import {
  fetchPizzas,
  selectPizzas,
  selectPizzaLoading,
  selectPizzaError,
} from '../../redux/pizzaSlice'

const categories = ['All', 'Veg', 'Non-Veg', 'Special']
const normalizeCategory = (value) =>
  value?.toString().toLowerCase().replace(/[^a-z]/g, '')

export default function PizzaList() {
  const dispatch = useDispatch()
  const pizzas = useSelector(selectPizzas)
  const loading = useSelector(selectPizzaLoading)
  const error = useSelector(selectPizzaError)
  const [selectedCategory, setSelectedCategory] = useState('All')

  useEffect(() => {
    dispatch(fetchPizzas())
  }, [dispatch])

  const filteredPizzas = useMemo(() => {
    if (!pizzas?.length) return []
    if (selectedCategory === 'All') return pizzas
    const filterKey = normalizeCategory(selectedCategory)
    return pizzas.filter((pizza) =>
      normalizeCategory(pizza.category).includes(filterKey)
    )
  }, [pizzas, selectedCategory])

  if (loading) return <Loader fullScreen />

  if (error) {
    return (
      <div className="p-6 max-w-4xl mx-auto">
        <div className="rounded-3xl border border-red-200 bg-red-50 p-6 text-red-700 shadow-sm">
          <h2 className="text-xl font-semibold mb-2">Unable to load pizzas</h2>
          <p>{error}</p>
        </div>
      </div>
    )
  }

  return (
    <div className="p-6 max-w-7xl mx-auto">
      <div className="mb-8 flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Pizza Menu</h1>
          <p className="mt-2 text-gray-500 max-w-2xl">
            Browse freshly prepared pizzas, filter by category, and start your order.
          </p>
        </div>
        <div className="flex flex-wrap gap-3">
          {categories.map((category) => (
            <button
              key={category}
              type="button"
              onClick={() => setSelectedCategory(category)}
              className={`rounded-full px-4 py-2 text-sm font-medium transition ${
                selectedCategory === category
                  ? 'bg-primary-600 text-white shadow-lg'
                  : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
              }`}
            >
              {category}
            </button>
          ))}
        </div>
      </div>

      {!filteredPizzas.length ? (
        <div className="rounded-3xl border border-dashed border-slate-300 bg-slate-50 p-10 text-center">
          <p className="text-lg font-semibold text-slate-900">
            No pizzas found for “{selectedCategory}”.
          </p>
          <p className="mt-2 text-gray-500">Try another category or check back later.</p>
          <button
            type="button"
            onClick={() => setSelectedCategory('All')}
            className="mt-6 rounded-full bg-primary-600 px-5 py-2.5 text-sm font-semibold text-white hover:bg-primary-700"
          >
            Show all pizzas
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 xl:grid-cols-3">
          {filteredPizzas.map((pizza) => (
            <PizzaCard key={pizza._id} pizza={pizza} />
          ))}
        </div>
      )}
    </div>
  )
}
